// Test retry function
async function testRetry() {
    let attempts = 0;
    const failTwice = async () => {
        attempts++;
        if (attempts < 3) throw new Error('fail');
        return 'success';
    };
    const result = await retry(failTwice, 5);
    console.assert(result === 'success', `Expected success, got ${result}`);
    console.assert(attempts === 3, `Expected 3 attempts, got ${attempts}`);

    // Test exhausting retries
    try {
        await retry(() => { throw new Error('always fail'); }, 2);
        console.assert(false, 'Should have thrown');
    } catch (e) {
        console.assert(e.message === 'always fail', 'Should preserve error');
    }
    console.log('ALL TESTS PASSED');
}
testRetry();

