function Animal(name) { this.name = name; }
Animal.prototype.speak = function() { return this.name + ' speaks'; };
const dog = new Animal('Rex');
assert_eq = (a, b, msg) => { if (a !== b) { console.error(msg + ': ' + a + ' !== ' + b); process.exit(1); } };
assert_eq(dog.speak(), 'Rex speaks', 'speak method');
assert_eq(dog.__proto__ === Animal.prototype, true, 'proto chain');
assert_eq(dog.constructor === Animal, true, 'constructor');
assert_eq(dog.hasOwnProperty('name'), true, 'own property');
assert_eq(dog.hasOwnProperty('speak'), false, 'inherited property');
console.log('ALL TESTS PASSED');
